import { useState, useEffect } from "react";

function App() {
  const [tarefa, setTarefa] = useState("");
  const [editandoIndex, setEditandoIndex] = useState(null);
  const [textoEditado, setTextoEditado] = useState("");
  const [filtro, setFiltro] = useState("todas");

  const [lista, setLista] = useState(() => {
    const tarefasSalvas = localStorage.getItem("tarefas");
    return tarefasSalvas ? JSON.parse(tarefasSalvas) : [];
  });

  useEffect(() => {
    localStorage.setItem("tarefas", JSON.stringify(lista));
  }, [lista]);

  function adicionarTarefa() {
    if (tarefa.trim() === "") return;
    const novaTarefa = { texto: tarefa, concluida: false };
    setLista([...lista, novaTarefa]);
    setTarefa("");
  }

  function removerTarefa(index) {
    setLista(lista.filter((_, i) => i !== index));
  }

  function toggleTarefa(index) {
    setLista(
      lista.map((item, i) =>
        i === index ? { ...item, concluida: !item.concluida } : item
      )
    );
  }

  function iniciarEdicao(index) {
    setEditandoIndex(index);
    setTextoEditado(lista[index].texto);
  }

  function salvarEdicao(index) {
    setLista(
      lista.map((item, i) =>
        i === index ? { ...item, texto: textoEditado } : item
      )
    );
    setEditandoIndex(null);
    setTextoEditado("");
  }

  // Lista filtrada
  const listaFiltrada = lista.filter((item) => {
    if (filtro === "concluidas") return item.concluida;
    if (filtro === "pendentes") return !item.concluida;
    return true;
  });

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>📝 To-Do List</h1>

        {/* Botões de filtro com contadores ao vivo */}
        <div style={styles.filtros}>
          <button
            style={{
              ...styles.filtroButton,
              background: filtro === "todas" ? "#007bff" : "#ccc",
              color: filtro === "todas" ? "#fff" : "#000"
            }}
            onClick={() => setFiltro("todas")}
          >
            Total: {lista.length}
          </button>
          <button
            style={{
              ...styles.filtroButton,
              background: filtro === "concluidas" ? "#28a745" : "#ccc",
              color: filtro === "concluidas" ? "#fff" : "#000"
            }}
            onClick={() => setFiltro("concluidas")}
          >
            Concluídas: {lista.filter((t) => t.concluida).length}
          </button>
          <button
            style={{
              ...styles.filtroButton,
              background: filtro === "pendentes" ? "#ffc107" : "#ccc",
              color: filtro === "pendentes" ? "#000" : "#000"
            }}
            onClick={() => setFiltro("pendentes")}
          >
            Pendentes: {lista.filter((t) => !t.concluida).length}
          </button>
        </div>

        {/* Input */}
        <div style={styles.inputArea}>
          <input
            style={styles.input}
            value={tarefa}
            onChange={(e) => setTarefa(e.target.value)}
            placeholder="Digite uma tarefa..."
          />
          <button style={styles.addButton} onClick={adicionarTarefa}>
            +
          </button>
        </div>

        {/* Lista */}
        <ul style={styles.lista}>
          {listaFiltrada.map((item, index) => (
            <li
              key={index}
              style={{
                ...styles.item,
                opacity: item.concluida ? 0.6 : 1,
                transform: item.concluida ? "scale(0.98)" : "scale(1)",
                transition: "0.2s"
              }}
            >
              {editandoIndex === index ? (
                <input
                  style={styles.input}
                  value={textoEditado}
                  onChange={(e) => setTextoEditado(e.target.value)}
                />
              ) : (
                <span
                  style={{
                    textDecoration: item.concluida ? "line-through" : "none",
                    color: item.concluida ? "#888" : "#000",
                    fontWeight: 500
                  }}
                >
                  {item.texto}
                </span>
              )}

              <div style={styles.actions}>
                <button
                  style={{
                    ...styles.checkButton,
                    background: item.concluida ? "#555" : "#28a745"
                  }}
                  onClick={() => toggleTarefa(index)}
                >
                  ✔
                </button>

                {editandoIndex === index ? (
                  <button
                    style={styles.saveButton}
                    onClick={() => salvarEdicao(index)}
                  >
                    💾
                  </button>
                ) : (
                  <button
                    style={styles.editButton}
                    onClick={() => iniciarEdicao(index)}
                  >
                    ✏️
                  </button>
                )}

                <button
                  style={styles.deleteButton}
                  onClick={() => removerTarefa(index)}
                >
                  ✖
                </button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

const styles = {
  page: {
    background: "#f0f4f8",
    minHeight: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "flex-start",
    paddingTop: 50,
    fontFamily: "Arial, sans-serif"
  },
  container: {
    background: "#fff",
    padding: 25,
    borderRadius: 15,
    boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
    width: 400,
    maxWidth: "90%"
  },
  title: {
    textAlign: "center",
    marginBottom: 15,
    color: "#4A90E2"
  },
  inputArea: {
    display: "flex",
    gap: 10,
    marginBottom: 20
  },
  input: {
    flex: 1,
    padding: 10,
    borderRadius: 10,
    border: "1px solid #ccc",
    outline: "none"
  },
  addButton: {
    padding: "10px 18px",
    borderRadius: 10,
    border: "none",
    background: "#4A90E2",
    color: "#fff",
    fontSize: 18,
    cursor: "pointer"
  },
  filtros: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: 20
  },
  filtroButton: {
    flex: 1,
    padding: "8px 0",
    margin: "0 5px",
    borderRadius: 10,
    border: "none",
    cursor: "pointer",
    fontWeight: 500,
    transition: "0.2s"
  },
  lista: {
    listStyle: "none",
    padding: 0
  },
  item: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: 12,
    borderRadius: 10,
    marginBottom: 10,
    background: "#f7f9fa",
    boxShadow: "0 2px 6px rgba(0,0,0,0.05)"
  },
  actions: {
    display: "flex",
    gap: 5
  },
  checkButton: {
    border: "none",
    color: "#fff",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold"
  },
  editButton: {
    background: "#F5A623",
    border: "none",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold"
  },
  saveButton: {
    background: "#50E3C2",
    border: "none",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold",
    color: "#fff"
  },
  deleteButton: {
    background: "#E94E77",
    color: "#fff",
    border: "none",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold"
  }
};

export default App;
